import { CrudErrors } from '@eicrud/shared/CrudErrors';
import { OrderByType } from '@eicrud/shared/interfaces';

export interface SortField {
  field: string;
  dir: 'asc' | 'desc';
}

function normalizeDir(raw: any): 'asc' | 'desc' {
  const str = String(raw).trim().toLowerCase();
  if (str === '-1') return 'desc';
  return str.startsWith('desc') ? 'desc' : 'asc';
}

export function flattenOrderBy(orderBy: OrderByType<any>): SortField[] {
  const subs = Array.isArray(orderBy) ? orderBy : [orderBy];
  const fields: SortField[] = [];
  for (const sub of subs) {
    if (!sub) continue;
    for (const field of Object.keys(sub)) {
      fields.push({ field, dir: normalizeDir(sub[field]) });
    }
  }
  return fields;
}

export function getSortString(sortFields: SortField[]): string {
  return sortFields.map((f) => `${f.field}:${f.dir}`).join(',');
}

/**
 * Appends the entity id field as a final ascending tiebreaker when it isn't
 * already part of orderBy, so keyset comparisons always have a unique cursor.
 */
export function withIdTiebreaker(
  sortFields: SortField[],
  idField: string,
): SortField[] {
  if (sortFields.some((f) => f.field === idField)) {
    return sortFields;
  }
  return [...sortFields, { field: idField, dir: 'asc' }];
}

export function decodeCursor(cursor: string): Record<string, any> {
  let json: any;
  try {
    const decoded = Buffer.from(cursor, 'base64').toString('utf8');
    json = JSON.parse(decoded);
  } catch (e) {
    throw new BadRequestException(CrudErrors.INVALID_CURSOR.str());
  }
  if (!json || typeof json !== 'object' || Array.isArray(json)) {
    throw new BadRequestException(CrudErrors.INVALID_CURSOR.str());
  }
  return json;
}

export function validateCursor(
  cursorData: Record<string, any>,
  sortFields: SortField[],
  idField: string,
) {
  const expectedSort = getSortString(sortFields);
  if (cursorData.__sort !== expectedSort) {
    throw new BadRequestException(CrudErrors.CURSOR_SORT_MISMATCH.str());
  }
  if (cursorData[idField] === undefined || cursorData[idField] === null) {
    throw new BadRequestException(CrudErrors.CURSOR_MISSING_ID.str());
  }
  for (const f of sortFields) {
    if (cursorData[f.field] === undefined) {
      throw new BadRequestException(CrudErrors.INVALID_CURSOR.str());
    }
  }
}

export function buildKeysetPredicate(
  sortFields: SortField[],
  cursorData: Record<string, any>,
): any {
  const orClauses = [];
  for (let i = 0; i < sortFields.length; i++) {
    const andClauses = [];
    for (let j = 0; j < i; j++) {
      const eq = sortFields[j];
      andClauses.push({ [eq.field]: cursorData[eq.field] });
    }
    const cur = sortFields[i];
    const op = cur.dir === 'desc' ? '$lt' : '$gt';
    andClauses.push({ [cur.field]: { [op]: cursorData[cur.field] } });
    orClauses.push(
      andClauses.length > 1 ? { $and: andClauses } : andClauses[0],
    );
  }
  return { $or: orClauses };
}

export function encodeCursor(
  lastRow: Record<string, any>,
  sortFields: SortField[],
  idField: string,
): string {
  const payload: Record<string, any> = {};
  for (const f of sortFields) {
    payload[f.field] = lastRow[f.field];
  }
  payload[idField] = lastRow[idField];
  payload.__sort = getSortString(sortFields);
  return Buffer.from(JSON.stringify(payload)).toString('base64');
}
